#include <stdio.h>

int main() {
    int age;
    printf("Enter your age: ");
    scanf("%d", &age);
    printf("Your age is: %d\n", age);
    return 0;
}

#include <stdio.h>
#define PI 3.14159

int main() {
    int radius = 5;
    float area = PI * radius * radius;
    printf("Area: %f\n", area);
    return 0;
}

#include <stdio.h>

int main() {
    int a, b, sum;
    printf("Enter two numbers: ");
    scanf("%d %d", &a, &b);
    sum = a + b;
    printf("Sum: %d\n", sum);
    return 0;
}

#include <stdio.h>

int main() {
    printf("Size of int: %lu bytes\n", sizeof(int));
    printf("Size of float: %lu bytes\n", sizeof(float));
    printf("Size of double: %lu bytes\n", sizeof(double));
    return 0;
}

#include <stdio.h>

int main() {
    char c;
    printf("Enter a character: ");
    c = getchar();
    printf("You entered: ");
    putchar(c);
    return 0;
}

#include <stdio.h>

int globalVar = 100; // Global variable

void display() {
    int localVar = 50; // Local variable
    printf("Global: %d, Local: %d\n", globalVar, localVar);
}

int main() {
    display();
    // printf("%d", localVar); // Error: localVar is not accessible here
    return 0;
}

#include <stdio.h>

int main() {
    int i;
    float f;
    char c;
    printf("Enter int, float, and char: ");
    scanf("%d %f %c", &i, &f, &c);
    printf("Integer: %d, Float: %f, Char: %c\n", i, f, c);
    return 0;
}
